import React from 'react';
import { useDraggable } from '@dnd-kit/core';

function GuestCard({ guest, onDelete }) {
  const { attributes, listeners, setNodeRef, transform } = useDraggable({
    id: guest.id
  });

  const style = transform ? {
    transform: `translate(${transform.x}px, ${transform.y}px)`
  } : undefined;

  const extraFields = Object.entries(guest)
    .filter(([k]) => !['id', 'tableId', 'name'].includes(k))
    .slice(0, 2);

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="guest-card"
      {...listeners}
      {...attributes}
    >
      <div>{guest.name}</div>
      {extraFields.length > 0 && (
        <div className="guest-info">
          {extraFields.map(([k, v]) => `${k}: ${v}`).join(' | ')}
        </div>
      )}
      {onDelete && (
        <div className="guest-actions">
          <button className="delete-btn" onClick={(e) => {
            e.stopPropagation();
            onDelete(guest.id);
          }}>Delete</button>
        </div>
      )}
    </div>
  );
}

function GuestList({ guests, onDelete }) {
  return (
    <div className="guest-sidebar">
      <h2>Unassigned Guests ({guests.length})</h2>
      <div className="guest-list">
        {guests.map(guest => (
          <GuestCard key={guest.id} guest={guest} onDelete={onDelete} />
        ))}
        {guests.length === 0 && (
          <div style={{ color: '#999', textAlign: 'center', padding: 20 }}>
            No unassigned guests
          </div>
        )}
      </div>
    </div>
  );
}

export default GuestList;
